import{_ as r,o as t,c as s,j as e,a as o,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"0.综述","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/Transcend Fate/0.综述.md","filePath":"4.资源分区/7.物品与装备/6.套装/Transcend Fate/0.综述.md"}'),p={name:"4.资源分区/7.物品与装备/6.套装/Transcend Fate/0.综述.md"};function d(i,a,_,c,l,h){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"_0-综述",tabindex:"-1"},[o("0.综述 "),e("a",{class:"header-anchor",href:"#_0-综述","aria-label":'Permalink to "0.综述"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"新世短歌039")])])],-1),n('<h1 id="_0-综述-1" tabindex="-1">0.综述 <a class="header-anchor" href="#_0-综述-1" aria-label="Permalink to &quot;0.综述&quot;">​</a></h1><p>0.综述<br> 当星球意志将人类宣判为星球之癌，海啸、火山、瘟疫尽数具现为狰狞的灾厄兽，一场关乎种族存续的肃清战争，骤然降临。</p><p>人们亲眼目睹，陆地刹那沦为海藻的囚笼；城市被滔天烈焰焚为焦土，灰烬旋即被暴雨冲刷殆尽。<br> 数百万民众被未知的灾厄兽吞噬心智，最终走向自我毁灭；大地震颤间，一个国家连同其千年历史，彻底被砾石掩埋。<br> 见证那仅存于学者猜测、不可理解更无从反抗的存在将希望扼杀于摇篮。</p><p>灾厄兽的铁蹄踏碎了人类的文明幻梦，也撕碎了人类自封地球霸主的虚妄，灾难重伤了人们，却也唤醒了深埋于人类基因深处，对灾厄最原始的反抗本能。</p><p>人类开始向一切可能求索反击的力量，无论已知未知，但凡可行，便倾尽所有。<br> 直到人类第一次击落了一只灾厄兽，人们发现，这些灾厄兽的残躯，仍然具有其主人生前的部分能力。<br> 于是，Transcend Fate系列武装，应运而生。</p><p>为了战胜灾厄兽，人类首先需要理解它们，在这样的决意之下，灾厄兽根据其影响被简单粗暴的分为了：<br> Exceed级：个体可以对一座城市造成不可逆转的彻底性打击，以至于将一个城市转变为其巢穴，当遇到等级为Exceed级的灾厄兽时，需要数个大型组织进行一场集体狩猎将其讨伐。<br> Apotheosis级：可以对一个国家施加灾难性的影响，足矣令一个国家彻底变为无人区，当遇到等级为Apotheosis级的灾厄兽时，需要一个国家以无数个人，无数把枪，流无数血，丧无数命，才能成功讨伐。<br> Moira级：当检测到等级为Moira的灾厄兽时，推荐立刻放弃抵抗并且自杀，这大概率是以人类姿态死亡的最好结局。</p><p>击杀、解析并逆向工程灾厄兽本身，这些由星球法则具象化的恐怖造物，其躯体里流淌着颠覆常规物理的能量，其利爪尖裹挟着改写生态的法则，逐步变为人类对抗灾厄的力量。人类的研究者们在废墟之上匍匐前行，于战火间隙拆解灾厄兽的残骸，从exceed级灾厄兽的核心中解析能源，从apotheosis级巨兽的核心里破译法则，甚至试图窃取Moira级存在的碎片。他们将这些掠夺而来的力量根源，强行转化为可被人类掌控的装甲与兵器。</p><p>但任何的差错便足以掀起足以毁灭世界的变化，在主神观测无数时间线的数据库中，除了成功战胜所有灾厄兽的世界线，同时还隐藏着无数文明的残响：人类耗尽最后资源造出初代对灾厄装甲，却在apotheosis级灾厄兽的威能中全军覆没的世界线；研究者们突破技术桎梏，打造出能硬撼Moira级存在的终极机型，却因内部分裂错失生机的世界线；人类以半数文明覆灭为代价，彻底逆转灾厄兽的力量法则，为自己赢得了来之不易的存续权的世界线</p><p>主神将这些散落在不同时间线的技术成果、未竟构想与人文历史悉数收集，以超越维度的力量，将那些停留在理论阶段的设计落地，将那些在战场嘶吼的武装塑造，将那些未能实现的终极方案化为现实。</p><p>每一件“Transcend Fate”武装，都代表着人类为超越灭亡命运而踏出的每一步。它们是已发生历史的证明；它们是未竟可能性的馈赠；它们更是当前世界线人类的最后底牌。在这场星球意志主导的肃清战争中，人类没有退路，唯有握紧这些凝聚着无数生命与希望的兵器，向着被既定的灭亡命运发起冲锋——为求生存，人类必须超越被星球划定的宿命。<br> “For Survival”</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const T=r(p,[["render",d]]);export{f as __pageData,T as default};
